#Preprocessorsimport numpy as npimport osimport matplotlib.pyplot as pltfrom ramanspy.preprocessing.denoise import SavGolfrom sklearn.pipeline import make_pipelineimport chemometrics as cmimport ramanspyfrom ramanspy.preprocessing.misc import Cropperfrom scipy.signal import savgol_filterfrom collections import defaultdictdef mean_centering(spectral_data):    """    Apply mean centering to the spectral data by subtracting the mean of each spectrum.        Parameters:        spectral_data (numpy.ndarray): The spectral data array to mean-center.            Returns:        numpy.ndarray: The mean-centered spectral data.    """    mean_spectrum = np.mean(spectral_data, axis=1).reshape(-1, 1)  # Calculate mean for each spectrum    mean_centered_spectra = spectral_data - mean_spectrum    return mean_centered_spectradef preprocess_pipeline_1(sample_spectra, spectra_dir, crop_region=(500, 1800),                          savgol_window=13, savgol_polyorder=2, emsc_p_order=2,                          emsc_asym_factor=0.1, deriv_order=1):    """    Preprocess Raman spectra using cropping, Savitzky-Golay smoothing, EMSC, and mean-centering.    Parameters:        sample_spectra (dict): Raw spectra by sample name.        spectra_dir (str): Output path to save plots.        crop_region (tuple): (min, max) wavenumber for cropping.        savgol_window (int): Window for Savitzky-Golay filter.        savgol_polyorder (int): Polynomial order for Savitzky-Golay filter.        emsc_p_order (int): Polynomial order for EMSC.        emsc_asym_factor (float): Asymmetry for EMSC ALS baseline.        deriv_order (int): Derivative order for Savitzky-Golay.    Returns:        dict: Preprocessed spectra by sample name.        list: Cropped axis.    """    import copy    from ramanspy.preprocessing.misc import Cropper    from sklearn.pipeline import make_pipeline    spectra_copy = copy.deepcopy(sample_spectra)    os.makedirs(spectra_dir, exist_ok=True)    for sample_name, spectra in spectra_copy.items():        # === Step 1: Crop        cropper = Cropper(region=crop_region)        cropped_spectra = [cropper.apply(spectrum) for spectrum in spectra]        cropped_axis = cropped_spectra[0].spectral_axis        # === Step 2: Savitzky-Golay smoothing / deriv        savgol = SavGol(window_length=savgol_window, polyorder=savgol_polyorder, deriv=deriv_order)        smoothed_spectra = savgol.apply(cropped_spectra)        # === Step 3: EMSC correction        spectral_matrix = np.array([s.spectral_data for s in smoothed_spectra])        emsc_pipeline = make_pipeline(            cm.Emsc(p_order=emsc_p_order, normalize=False, algorithm='als', asym_factor=emsc_asym_factor)        )        emsc_corrected = emsc_pipeline.fit_transform(spectral_matrix)        # === Step 4: Mean Centering        emsc_centered = mean_centering(emsc_corrected)        # === Step 5: Convert back to Spectrum objects        final_spectra = [            ramanspy.Spectrum(data, cropped_axis)            for data in emsc_centered        ]        spectra_copy[sample_name] = final_spectra        # === Plot cropped        plt.figure(figsize=(8, 5))        for spec in cropped_spectra:            plt.plot(spec.spectral_axis, spec.spectral_data, color="blue", alpha=0.4)        plt.title(f"Cropped Spectra: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.savefig(os.path.join(spectra_dir, f"{sample_name}_Cropped.png"), dpi=300, bbox_inches="tight")        plt.close()        # === Plot EMSC + Mean Centered        plt.figure(figsize=(8, 5))        for spec in final_spectra:            plt.plot(spec.spectral_axis, spec.spectral_data, color="red", alpha=0.8)        plt.title(f"EMSC + Mean Centered: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.savefig(os.path.join(spectra_dir, f"{sample_name}_EMSCpreprocessed.png"), dpi=300, bbox_inches="tight")        plt.close()    return spectra_copy, cropped_axisdef snv_normalization(spectral_data):    """    Apply Standard Normal Variate (SNV) normalization to the given spectral data.    SNV = (X - mean(X)) / std(X)        Parameters:        spectral_data (numpy.ndarray): The spectral data array to normalize.    Returns:        numpy.ndarray: The SNV-normalized spectral data.    """    # Center and scale each spectrum    mean_spectrum = np.mean(spectral_data, axis=1).reshape(-1, 1)  # Calculate mean for each spectrum    std_spectrum = np.std(spectral_data, axis=1).reshape(-1, 1)    # Calculate std for each spectrum        # Apply SNV normalization    snv_spectra = (spectral_data - mean_spectrum) / std_spectrum    return snv_spectradef preprocess_pipeline_2(sample_spectra, spectra_dir, crop_region=(800, 1800), derivative_order=1):    """    Preprocesses Raman spectra using cropping, Savitzky-Golay derivative, SNV normalization, and mean centering.    """    import copy        spectra_copy = copy.deepcopy(sample_spectra)    for sample_name, spectra in spectra_copy.items():        differentiated_spectra = []        for spectrum in spectra:            # Crop            cropper = Cropper(region=crop_region)            cropped_spectrum = cropper.apply(spectrum)            # Process            spectral_data = cropped_spectrum.spectral_data            differentiated_data = savgol_filter(spectral_data, polyorder=2, window_length=13, deriv=derivative_order)            snv_data = snv_normalization(differentiated_data.reshape(1, -1))            mean_centered_data = mean_centering(snv_data.reshape(1, -1))            processed_spectrum = ramanspy.Spectrum(mean_centered_data.flatten(), cropped_spectrum.spectral_axis)            differentiated_spectra.append(processed_spectrum)        spectra_copy[sample_name] = differentiated_spectra        # Plot individual        plt.figure(figsize=(8, 5))        for s in differentiated_spectra:            plt.plot(s.spectral_axis, s.spectral_data, alpha=0.7)        plt.title(f"Processed: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.savefig(os.path.join(spectra_dir, f"{sample_name}_processed.png"), dpi=300, bbox_inches="tight")        plt.close()    # Final overlay plot    plt.figure(figsize=(8, 5))    for sample_name, spectra in spectra_copy.items():        for s in spectra:            plt.plot(s.spectral_axis, s.spectral_data, alpha=0.6)    plt.title("Overlay of All Preprocessed Spectra")    plt.xlabel("Raman Shift (cm⁻¹)")    plt.ylabel("Intensity")    plt.savefig(os.path.join(spectra_dir, "Overlay_Preprocessed.png"), dpi=300, bbox_inches="tight")    plt.close()    cropped_axis = list(spectra_copy.values())[0][0].spectral_axis    return spectra_copy, cropped_axisdef group_preprocess(sample_spectra, sample_groups, spectra_dir,                     crop_region=(500, 1800),                     emsc_p_order=6, emsc_asym_factor=0.1,                     deriv_order=1):    """    Group-level preprocessing:    Crop → SavGol Derivative → EMSC → Mean Center → Average    Parameters:    -----------    sample_spectra : dict        Sample ID → list of ramanspy.Spectrum objects    sample_groups : dict        Group ID → list of sample IDs    spectra_dir : str        Directory to save plots    crop_region : tuple        (min, max) cropping region    emsc_p_order : int        Polynomial order for EMSC    emsc_asym_factor : float        Asymmetry factor for EMSC ALS    deriv_order : int        Derivative order for Savitzky-Golay    Returns:    --------    group_avg_spectra : dict        Group ID → list containing one averaged Spectrum object    cropped_axis : ndarray        The cropped spectral axis    """        from ramanspy import Spectrum           os.makedirs(spectra_dir, exist_ok=True)    group_avg_spectra = {}    cropped_axis = None    group_replicates = {}    for group_id, sample_ids in sample_groups.items():        preprocessed = []        for sid in sorted(sample_ids):            spectra = sample_spectra.get(sid)            if not spectra:                print(f"⚠️ Sample '{sid}' missing or has no spectra. Skipping.")                continue            for spectrum in spectra:                # === Crop                cropper = Cropper(region=crop_region)                cropped = cropper.apply(spectrum)                if cropped_axis is None:                    cropped_axis = cropped.spectral_axis                # === Derivative via SavGol                savgol = SavGol(window_length=9, polyorder=2, deriv=deriv_order)                smoothed = savgol.apply([cropped])[0]                preprocessed.append(smoothed.spectral_data)        if not preprocessed:            print(f"⚠️ Group '{group_id}' has no valid spectra. Skipping.")            continue        # === Apply EMSC to all group spectra        spectral_matrix = np.array(preprocessed)        pipeline = make_pipeline(            cm.Emsc(p_order=emsc_p_order, background=None, normalize=False,                    algorithm='als', asym_factor=emsc_asym_factor)        )        emsc_corrected = pipeline.fit_transform(spectral_matrix)        # === Mean Centering        emsc_corrected = mean_centering(emsc_corrected)        # === Average        group_avg = np.mean(emsc_corrected, axis=0)        group_avg_spectra[group_id] = [Spectrum(group_avg, cropped_axis)]  # wrapped in list ✅        group_replicates[group_id] = [Spectrum(y, cropped_axis) for y in emsc_corrected]        # === Plot        plt.figure(figsize=(8, 5))        for i, y in enumerate(emsc_corrected):            plt.plot(cropped_axis, y, alpha=0.3, label=f"{group_id}-{i+1}")        plt.plot(cropped_axis, group_avg, color="black", linewidth=2, label=f"{group_id} Avg")        plt.title(f"Group {group_id} - SavGol Deriv + EMSC + Mean Centered")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        plt.savefig(os.path.join(spectra_dir, f"{group_id}_emsc_avg.png"), dpi=300, bbox_inches="tight")        plt.close()    return group_avg_spectra, cropped_axis, group_replicatesdef group_preprocess_2(sample_spectra, sample_groups, spectra_dir="Group_Preprocessed_Averages",                       crop_region=(800, 1800), derivative_order=1):    """    Group-level preprocessing using Crop → Savitzky-Golay Derivative → SNV → Mean Centering.    Parameters:    -----------    sample_spectra : dict        Sample ID → list of ramanspy.Spectrum objects    sample_groups : dict        Group ID → list of sample IDs (e.g., '1': ['1-1', '1-2', '1-3'])    spectra_dir : str        Path to save individual and overlay plots    crop_region : tuple        Region to crop (start, end) in cm⁻¹    derivative_order : int        Derivative order for Savitzky-Golay filter    Returns:    --------    group_avg_spectra : dict        Group ID → averaged, preprocessed Spectrum object    cropped_axis : np.ndarray        Cropped spectral axis    """    os.makedirs(spectra_dir, exist_ok=True)    group_avg_spectra = {}    cropped_axis = None    for group_id, sample_ids in sample_groups.items():        preprocessed = []        for sid in sorted(sample_ids):            spectra = sample_spectra.get(sid)            if not spectra:                print(f"⚠️ Sample '{sid}' missing or has no spectra. Skipping.")                continue            for spectrum in spectra:                # Crop                cropper = Cropper(region=crop_region)                cropped = cropper.apply(spectrum)                if cropped_axis is None:                    cropped_axis = cropped.spectral_axis                y = cropped.spectral_data                # Savitzky-Golay derivative                y_deriv = savgol_filter(y, polyorder=2, window_length=13, deriv=derivative_order)                # SNV normalization                y_snv = snv_normalization(y_deriv.reshape(1, -1))                # Mean centering                y_mc = mean_centering(y_snv).flatten()                preprocessed.append(y_mc)        if not preprocessed:            print(f"⚠️ Group '{group_id}' has no valid spectra. Skipping.")            continue        # Average preprocessed spectra        group_array = np.array(preprocessed)        avg = np.mean(group_array, axis=0)        group_avg_spectra[group_id] = ramanspy.Spectrum(avg, cropped_axis)        # Plot        plt.figure(figsize=(8, 5))        for i, y_proc in enumerate(group_array):            plt.plot(cropped_axis, y_proc, alpha=0.3, label=f"{group_id}-{i+1}")        plt.plot(cropped_axis, avg, color="black", linewidth=2, label=f"{group_id} Avg")        plt.title(f"Group {group_id} - SavGol Deriv + SNV + Mean Centered")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        plt.savefig(os.path.join(spectra_dir, f"{group_id}_deriv_snv_meancentered_avg.png"), dpi=300, bbox_inches="tight")        plt.close()    return group_avg_spectra, cropped_axisdef avg_y_block(gcms_df):    """    Average the Y block (GC-MS or metadata) across replicate samples by group ID.    Parameters:    -----------    gcms_df : pd.DataFrame        Original target dataframe with replicate sample IDs as index (e.g., '1-1', '1-2').    Returns:    --------    pd.DataFrame        Group-averaged GC-MS data, indexed by group ID (e.g., '1', '2').    """    # Create a group column by removing suffix after '-'    df = gcms_df.copy()    df['Group'] = df.index.to_series().apply(lambda sid: sid.split("-")[0])        # Group by group ID and average    grouped_df = df.groupby("Group").mean()        return grouped_df